from dataclasses import dataclass
from datetime import datetime
from typing import Dict, Any

@dataclass
class PromptVersion:
    id: str
    version: str
    template: str
    created_at: datetime
    metadata: Dict[str, Any]
    metrics: Dict[str, float]

PROMPTS = {
    "sentiment_v1": PromptVersion(
        id="sentiment",
        version="1.0",
        template="Classify: {text}\nOutput: positive/negative/neutral",
        created_at=datetime(2024, 1, 1),
        metadata={"model": "gpt-4", "temperature": 0},
        metrics={"accuracy": 0.85}
    ),
    "sentiment_v2": PromptVersion(
        id="sentiment",
        version="2.0",
        template="[few-shot version]",
        created_at=datetime(2024, 6, 1),
        metadata={"model": "gpt-4", "temperature": 0},
        metrics={"accuracy": 0.92}
    ),
}

def get_prompt(name: str, version: str = "latest") -> PromptVersion:
    if version == "latest":
        versions = [p for p in PROMPTS.values() if p.id == name]
        return max(versions, key=lambda x: x.created_at)
    return PROMPTS.get(f"{name}_v{version}")

from dataclasses import dataclass
from typing import Dict, Optional
from datetime import datetime
import json
from pathlib import Path

@dataclass
class PromptVersion:
    template: str
    version: str
    created_at: datetime
    metadata: Dict

class PromptManager:
    """Manage prompt versions and A/B testing."""

    def __init__(self, storage_path: str = "./prompts"):
        self.storage_path = Path(storage_path)
        self.storage_path.mkdir(exist_ok=True)
        self.prompts: Dict[str, Dict[str, PromptVersion]] = {}

    def register(
        self,
        name: str,
        template: str,
        version: str,
        metadata: Optional[Dict] = None
    ) -> None:
        """Register a new prompt version."""
        if name not in self.prompts:
            self.prompts[name] = {}

        self.prompts[name][version] = PromptVersion(
            template=template,
            version=version,
            created_at=datetime.now(),
            metadata=metadata or {}
        )

    def get(self, name: str, version: str = "latest") -> PromptVersion:
        """Get a prompt by name and version."""
        if name not in self.prompts:
            raise KeyError(f"Prompt '{name}' not found")

        versions = self.prompts[name]

        if version == "latest":
            return max(versions.values(), key=lambda x: x.created_at)

        if version not in versions:
            raise KeyError(f"Version '{version}' not found for prompt '{name}'")

        return versions[version]

    def save(self) -> None:
        """Save prompts to disk."""
        data = {}
        for name, versions in self.prompts.items():
            data[name] = {
                v: {
                    "template": pv.template,
                    "version": pv.version,
                    "created_at": pv.created_at.isoformat(),
                    "metadata": pv.metadata
                }
                for v, pv in versions.items()
            }

        with open(self.storage_path / "prompts.json", "w") as f:
            json.dump(data, f, indent=2)

    def load(self) -> None:
        """Load prompts from disk."""
        path = self.storage_path / "prompts.json"
        if not path.exists():
            return

        with open(path) as f:
            data = json.load(f)

        for name, versions in data.items():
            for v, pv_data in versions.items():
                self.prompts.setdefault(name, {})[v] = PromptVersion(
                    template=pv_data["template"],
                    version=pv_data["version"],
                    created_at=datetime.fromisoformat(pv_data["created_at"]),
                    metadata=pv_data["metadata"]
                )


# Usage
manager = PromptManager()
manager.register(
    name="summarize",
    version="1.0",
    template="Summarize this text in {num_sentences} sentences:\n{text}",
    metadata={"author": "team", "tested": True}
)

prompt = manager.get("summarize")
formatted = prompt.template.format(num_sentences=3, text="Long text here...")

from dataclasses import dataclass, field
from typing import List, Dict, Optional
import re

@dataclass
class PromptTemplate:
    """Reusable prompt template with variable substitution."""

    name: str
    template: str
    system_prompt: Optional[str] = None
    examples: List[Dict[str, str]] = field(default_factory=list)

    def format(self, **kwargs) -> str:
        """Format template with provided variables."""
        required = set(re.findall(r'\{(\w+)\}', self.template))
        provided = set(kwargs.keys())
        missing = required - provided

        if missing:
            raise ValueError(f"Missing variables: {missing}")

        return self.template.format(**kwargs)

    def to_messages(self, **kwargs) -> List[Dict[str, str]]:
        """Convert to chat message format."""
        messages = []

        if self.system_prompt:
            messages.append({
                "role": "system",
                "content": self.system_prompt
            })

        for example in self.examples:
            messages.append({"role": "user", "content": example["input"]})
            messages.append({"role": "assistant", "content": example["output"]})

        messages.append({
            "role": "user",
            "content": self.format(**kwargs)
        })

        return messages


# Usage
classification_template = PromptTemplate(
    name="sentiment_classification",
    system_prompt="You are a sentiment classifier.",
    template="Classify the sentiment of: {text}\nOutput: positive/negative/neutral",
    examples=[
        {"input": "Classify: I love this!", "output": "positive"},
        {"input": "Classify: This is terrible", "output": "negative"}
    ]
)

messages = classification_template.to_messages(text="Great product!")

def get_response_with_retry(prompt: str, max_retries: int = 3) -> str:
    """Retry with increasingly specific prompts."""
    prompts = [
        prompt,
        f"{prompt}\n\nIMPORTANT: Follow exact format above.",
        f"{prompt}\n\nExample:\n{get_example()}\n\nMatch this format exactly.",
    ]

    for i, p in enumerate(prompts[:max_retries]):
        response = call_llm(p)
        if validate_response(response):
            return response
        logger.warning(f"Retry {i+1}: Invalid format")

    raise ValueError("Failed after retries")

from pydantic import BaseModel, Field from typing import List, Optional from enum import Enum
class SentimentEnum(str, Enum): POSITIVE = "positive" NEGATIVE = "negative" NEUTRAL = "neutral"
class SentimentResult(BaseModel): sentiment: SentimentEnum = Field(description="positive, negative, or neutral") confidence: float = Field(ge=0, le=1) keywords: List[str] = Field(description="Key words that influenced the classification")
PROMPT = f"""Analyze the sentiment of: {{input}}
Respond with valid JSON matching this schema: ```json {SentimentResult.model_json_schema()} ```
Output only the JSON, no additional text."""

from typing import Type, TypeVar, Optional
from pydantic import BaseModel, ValidationError
import json
import re

T = TypeVar('T', bound=BaseModel)

class StructuredOutputHandler:
    """Handle structured output from LLM responses."""

    @staticmethod
    def extract_json(text: str) -> Optional[str]:
        """Extract JSON from text that may contain other content."""
        # Try to find JSON in code blocks
        code_block_match = re.search(r'```(?:json)?\s*([\s\S]*?)```', text)
        if code_block_match:
            return code_block_match.group(1).strip()

        # Try to find raw JSON
        json_match = re.search(r'\{[\s\S]*\}', text)
        if json_match:
            return json_match.group(0)

        return None

    @staticmethod
    def parse(text: str, schema: Type[T]) -> T:
        """Parse LLM output into Pydantic model."""
        json_str = StructuredOutputHandler.extract_json(text)

        if not json_str:
            raise ValueError("No JSON found in response")

        try:
            data = json.loads(json_str)
            return schema.model_validate(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON: {e}")
        except ValidationError as e:
            raise ValueError(f"Schema validation failed: {e}")

    @staticmethod
    def create_prompt(task: str, schema: Type[BaseModel]) -> str:
        """Create prompt that requests structured output."""
        schema_json = json.dumps(schema.model_json_schema(), indent=2)

        return f"""{task}

Respond with valid JSON matching this schema:
```json
{schema_json}
```

Output only the JSON, no additional text."""


def get_validated_response(
    prompt: str,
    schema: Type[BaseModel],
    max_retries: int = 3
) -> BaseModel:
    """Get response with validation and retries."""
    for attempt in range(max_retries):
        response = call_llm(prompt)
        validated = validate_json_response(response, schema)

        if validated:
            return validated

        # Add feedback for retry
        prompt = f"""{prompt}

Previous response was invalid. Ensure output is valid JSON
matching the schema exactly."""

    raise ValueError(f"Failed to get valid response after {max_retries} attempts")

